/// \file
/// This file declares the targeting of the Machinelegalizer class for
/// Xtensa.
/// \todo This should be generated by TableGen.
//===----------------------------------------------------------------------===//

#ifndef LLVM_LIB_TARGET_XTENSA_XTENSAMACHINELEGALIZER_H
#define LLVM_LIB_TARGET_XTENSA_XTENSAMACHINELEGALIZER_H

#include "llvm/CodeGen/GlobalISel/GISelChangeObserver.h"
#include "llvm/CodeGen/GlobalISel/LegalizerHelper.h"
#include "llvm/CodeGen/GlobalISel/LegalizerInfo.h"
#include "llvm/CodeGen/MachineRegisterInfo.h"

namespace llvm {

class XtensaSubtarget;

/// This class provides the information for the target register banks.
class XtensaLegalizerInfo : public LegalizerInfo {
public:
  XtensaLegalizerInfo(const XtensaSubtarget &ST);

  bool legalizeCustom(LegalizerHelper &Helper, MachineInstr &MI) const override;

  bool legalizeIntrinsic(LegalizerHelper &Helper,
                         MachineInstr &MI) const override;

private:

bool legalizeConstant(MachineInstr &MI, MachineRegisterInfo &MRI, 
                      LegalizerHelper &Helper) const;

  const XtensaSubtarget *ST;

};
} // End llvm namespace.
#endif
